use std::collections::HashSet;
use std::io::{self, Write};

struct ConnectionTracker {
    seen_ids: HashSet<u64>,
}

impl ConnectionTracker {
    fn new() -> Self {
        ConnectionTracker { seen_ids: HashSet::new() }
    }

    fn record_id(&mut self, id: u64) -> bool {
        self.seen_ids.insert(id);
        true
    }

    fn has_already_seen(&self, id: u64) -> bool {
        self.seen_ids.contains(&id)
    }

    fn print_unique_count(&self) -> usize {
        self.seen_ids.len()
    }
}

fn main() -> io::Result<()> {
    let mut tracker = ConnectionTracker::new();
    tracker.record_id(100);
    tracker.record_id(250);
    tracker.record_id(100);

    println!("Connection IDs recorded successfully.");
    if tracker.has_already_seen(100) {
        println!("ID 100 was already present in the set.");
    }

    let count = tracker.print_unique_count();
    writeln!(io::stdout(), "Total unique connections tracked: {}", count)?;

    Ok(())
}

use std::collections::HashSet;

struct InstructionSet {
    unique_instructions: HashSet<u32>,
    sorted_bytecode: Vec<u32>,
}

impl InstructionSet {
    fn new() -> Self {
        InstructionSet {
            unique_instructions: HashSet::new(),
            sorted_bytecode: Vec::new(),
        }
    }

    fn add_instruction(&mut self, instruction: u32) {
        if self.unique_instructions.insert(instruction) {
            self.sorted_bytecode.push(instruction);
            self.sorted_bytecode.sort();
        }
    }

    fn get_sorted_instructions(&self) -> &[u32] {
        &self.sorted_bytecode
    }

    fn check_for_duplicate(&self, instruction: u32) -> bool {
        !self.unique_instructions.contains(&instruction)
    }
}

fn main() {
    let mut instructions = InstructionSet::new();
    instructions.add_instruction(1024);
    instructions.add_instruction(50);
    instructions.add_instruction(200);
    instructions.add_instruction(50); 

    if instructions.check_for_duplicate(100) {
        println!("Instruction 100 is new and will be added.");
        instructions.add_instruction(100);
    } else {
        println!("Instruction 100 already exists.");
    }

    let sorted = instructions.get_sorted_instructions();
    println!("Available unique and sorted instructions: {:?}", sorted);
}

use std::collections::BTreeSet;

struct GameGrid {
    live_cells: BTreeSet<(i32, i32)>,
}

impl GameGrid {
    fn new() -> Self {
        GameGrid { live_cells: BTreeSet::new() }
    }

    fn add_cell(&mut self, x: i32, y: i32) {
        self.live_cells.insert((x, y));
    }

    fn remove_cell(&mut self, x: i32, y: i32) {
        self.live_cells.remove(&(x, y));
    }

    fn count_cells(&self) -> usize {
        self.live_cells.len()
    }
}

fn main() {
    let mut grid = GameGrid::new();
    grid.add_cell(10, 20);
    grid.add_cell(5, 8);
    grid.add_cell(-3, 1);

    println!("Initial cell count: {}", grid.count_cells());

    for i in 0..15 {
        if i % 3 == 0 {
            grid.add_cell(i as i32 + 1, i as i32);
        } else {
            let x = (i - 2) as i32;
            let y = (i / 2) as i32;
            grid.remove_cell(x, y);
        }
    }

    println!("Final cell count: {}", grid.count_cells());
}

use std::collections::{BTreeSet, HashSet};

struct RecordProcessor {
    seen_ids: BTreeSet<String>,
    unique_names: HashSet<String>,
}

impl RecordProcessor {
    fn new() -> Self {
        RecordProcessor {
            seen_ids: BTreeSet::new(),
            unique_names: HashSet::new(),
        }
    }

    fn process_row(&mut self, id: &str, name: &str) {
        self.seen_ids.insert(id.to_string());
        self.unique_names.insert(name.to_string());
    }

    fn print_sorted_ids(&self) {
        println!("--- Sorted Unique IDs (BTreeSet) ---");
        for id in &self.seen_ids {
            print!("{id}, ");
        }
        println!("");
    }

    fn print_all_names(&self) {
        println!("--- All Unique Names (HashSet) ---");
        for name in &self.unique_names {
            print!("{name}, ");
        }
        println!("");
    }
}

fn main() {
    let mut processor = RecordProcessor::new();

    processor.process_row("user103", "Alice");
    processor.process_row("user201", "Bob");
    processor.process_row("user103", "Charlie");
    processor.process_row("user300", "Alice");

    processor.print_sorted_ids();
    processor.print_all_names();
}

#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
struct SearchResult {
    path: String,
    size: u64,
}
impl std::fmt::Display for SearchResult {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "{}: {} bytes", self.path, self.size)
    }
}

use std::collections::BTreeSet;
use std::error::Error;

fn main() -> Result<(), Box<dyn Error>> {
    let mut found_files: BTreeSet<SearchResult> = BTreeSet::new();

    let file1 = SearchResult { path: "/src/main.rs".to_string(), size: 4096 };
    let file2 = SearchResult { path: "/Cargo.toml".to_string(), size: 1024 };
    let file3 = SearchResult { path: "/README.md".to_string(), size: 512 };

    found_files.insert(file1);
    found_files.insert(file2);
    found_files.insert(file3);

    println!("--- Unique and Sorted File Paths Found ---n");

    for result in found_files.iter() {
        println!("Found Object: {}", result);
    }

    Ok(())
}
